import React, { useState } from "react";

type PlainTextFormProps = {
  onSubmit: (text: string, tableSize: number) => void;
};

function PlainTextForm({ onSubmit }: PlainTextFormProps) {
  const [text, setText] = useState<string>("");
  const [tableSize, setTableSize] = useState<number>(8);

  return (
    <form
      onSubmit={(event) => {
        event.preventDefault();
        onSubmit(text, tableSize);
        // setText(""); // Clear the textarea after submission
      }}
      style={{ maxWidth: "400px", margin: "0 auto" }}
    >
      <label
        htmlFor="plaintext"
        style={{ display: "block", marginBottom: "8px" }}
      >
        Paste your guest list here (one name per line):
      </label>
      <textarea
        id="plaintext"
        value={text}
        onChange={(event) => {
          setText(event.target.value);
        }}
        rows={10}
        style={{ width: "100%", marginBottom: "12px", padding: "8px" }}
        placeholder="Guests..."
      />
      <label
        htmlFor="numberSelect"
        style={{ display: "block", marginBottom: "8px" }}
      >
        How many seats per table:
      </label>
      <select
        id="numberSelect"
        value={tableSize}
        onChange={(event) => {
          setTableSize(parseInt(event.target.value, 10));
        }}
        style={{ width: "100%", marginBottom: "12px", padding: "8px" }}
      >
        {[8, 10, 12].map((num) => (
          <option key={num} value={num}>
            {num}
          </option>
        ))}
      </select>
      <button type="submit" style={{ padding: "8px 16px" }}>
        Next
      </button>
    </form>
  );
}

export default PlainTextForm;
